  1	import * as React from 'react';
  2	import { isK8sGatewayHostValid } from '../../../utils/IstioConfigUtils';
  3	import { Button, ButtonVariant, FormGroup, FormSelect, FormSelectOption, TextInput } from '@patternfly/react-core';
  4	import { isValid } from '../../../utils/Common';
  5	import { ListenerForm } from '../K8sGatewayForm';
  6	import { Td, Tr } from '@patternfly/react-table';
  7	import { addSelectorLabels } from './ListenerList';
  8	import { K8sGatewayTLS, MAX_PORT, MIN_PORT } from '../../../types/IstioObjects';
  9	import { KialiIcon } from 'config/KialiIcon';
 10	
 11	type ListenerBuilderProps = {
 12	  index: number;
 13	  listener: ListenerForm;
 14	  onChange: (listenerForm: ListenerForm, i: number) => void;
 15	  onRemoveListener: (i: number) => void;
 16	};
 17	
 18	// Only HTTPRoute is supported in Istio
 19	export const protocols = ['HTTP', 'HTTPS'];
 20	// protocols which could require certificate
 21	export const protocolsCert = ['HTTPS'];
 22	export const SELECTOR = 'Selector';
 23	export const allowedRoutes = ['All', SELECTOR, 'Same'];
 24	export const TERMINATE = 'Terminate';
 25	export const tlsModes = [TERMINATE];
 26	
 27	export const isValidName = (name: string): boolean => {
 28	  return name !== undefined && name.length > 0;
 29	};
 30	
 31	export const isValidHostname = (hostname: string): boolean => {
 32	  return hostname !== undefined && hostname.length > 0 && isK8sGatewayHostValid(hostname);
 33	};
 34	
 35	export const isValidTLS = (protocol: string, tls?: K8sGatewayTLS): boolean => {
 36	  const tlsRequired = protocolsCert.includes(protocol);
 37	  if (!tls || !tlsRequired) {
 38	    return true;
 39	  }
 40	
 41	  for (const cert of tls.certificateRefs) {
 42	    const certsValid = tlsRequired ? cert.name?.length > 0 : true;
 43	    if (!certsValid) {
 44	      return false;
 45	    }
 46	  }
 47	
 48	  return true;
 49	};
 50	
 51	export const isValidPort = (port: string): boolean => {
 52	  return port.length > 0 && !isNaN(Number(port)) && Number(port) >= MIN_PORT && Number(port) <= MAX_PORT;
 53	};
 54	
 55	export const isValidSelector = (selector: string): boolean => {
 56	  return addSelectorLabels(selector)[0];
 57	};
 58	
 59	export const ListenerBuilder: React.FC<ListenerBuilderProps> = (props: ListenerBuilderProps) => {
 60	  const onAddHostname = (_event: React.FormEvent, value: string): void => {
 61	    const l = props.listener;
 62	    l.hostname = value.trim();
 63	
 64	    props.onChange(l, props.index);
 65	  };
 66	
 67	  const onAddPort = (_event: React.FormEvent, value: string): void => {
 68	    const l = props.listener;
 69	    l.port = value.trim();
 70	
 71	    props.onChange(l, props.index);
 72	  };
 73	
 74	  const onAddName = (_event: React.FormEvent, value: string): void => {
 75	    const l = props.listener;
 76	    l.name = value.trim();
 77	
 78	    props.onChange(l, props.index);
 79	  };
 80	
 81	  const onAddProtocol = (_event: React.FormEvent, value: string): void => {
 82	    const l = props.listener;
 83	    l.protocol = value.trim();
 84	
 85	    props.onChange(l, props.index);
 86	  };
 87	
 88	  const onAddFrom = (_event: React.FormEvent, value: string): void => {
 89	    const l = props.listener;
 90	    l.from = value.trim();
 91	
 92	    props.onChange(l, props.index);
 93	  };
 94	
 95	  const onAddSelectorLabels = (_event: React.FormEvent, value: string): void => {
 96	    const l = props.listener;
 97	    l.sSelectorLabels = value.trim();
 98	
 99	    props.onChange(l, props.index);
100	  };
101	
102	  const onAddTlsMode = (_event: React.FormEvent, value: string): void => {
103	    const listener = props.listener;
104	    listener.tlsMode = value.trim();
105	
106	    props.onChange(listener, props.index);
107	  };
108	
109	  const onAddTlsCert = (_event: React.FormEvent, value: string): void => {
110	    const listener = props.listener;
111	    listener.tlsCert = value.trim();
112	
113	    props.onChange(listener, props.index);
114	  };
115	
116	  const showTls = protocolsCert.includes(props.listener.protocol);
117	
118	  return (
119	    <>
120	      <Tr>
121	        <Td>
122	          <TextInput
123	            value={props.listener.name}
124	            type="text"
125	            id={`addName_${props.index}`}
126	            aria-describedby="add name"
127	            onChange={onAddName}
128	            validated={isValid(isValidName(props.listener.name))}
129	          />
130	        </Td>
131	
132	        <Td>
133	          <TextInput
134	            value={props.listener.hostname}
135	            type="text"
136	            id={`addHostname_${props.index}`}
137	            aria-describedby="add hostname"
138	            name="addHostname"
139	            onChange={onAddHostname}
140	            validated={isValid(isValidHostname(props.listener.hostname))}
141	          />
142	        </Td>
143	
144	        <Td>
145	          <TextInput
146	            value={props.listener.port}
147	            type="text"
148	            id={`addPort_${props.index}`}
149	            placeholder="80"
150	            aria-describedby="add port"
151	            name="addPortNumber"
152	            onChange={onAddPort}
153	            validated={isValid(isValidPort(props.listener.port))}
154	          />
155	        </Td>
156	
157	        <Td>
158	          <FormSelect
159	            value={props.listener.protocol}
160	            id={`addPortProtocol_${props.index}`}
161	            name="addPortProtocol"
162	            onChange={onAddProtocol}
163	          >
164	            {protocols.map((option, index) => (
165	              <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
166	            ))}
167	          </FormSelect>
168	        </Td>
169	
170	        <Td>
171	          <FormSelect value={props.listener.from} id={`addFrom_${props.index}`} name="addFrom" onChange={onAddFrom}>
172	            {allowedRoutes.map((option, index) => (
173	              <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
174	            ))}
175	          </FormSelect>
176	        </Td>
177	
178	        <Td>
179	          <TextInput
180	            id={`addSelectorLabels_${props.index}`}
181	            name="addSelectorLabels"
182	            isDisabled={props.listener.from !== SELECTOR}
183	            onChange={onAddSelectorLabels}
184	            validated={isValid(
185	              props.listener.from === SELECTOR ? isValidSelector(props.listener.sSelectorLabels) : undefined
186	            )}
187	          />
188	        </Td>
189	        <Td>
190	          <Button
191	            id={`deleteBtn_${props.index}`}
192	            variant={ButtonVariant.link}
193	            icon={<KialiIcon.Trash />}
194	            style={{ padding: 0 }}
195	            onClick={() => props.onRemoveListener(props.index)}
196	          />
197	        </Td>
198	      </Tr>
199	      {showTls && (
200	        <Tr>
201	          <Td colSpan={2}>
202	            <FormGroup label="TLS Mode" fieldId="addTlsMode" style={{ margin: '0.5rem 0' }}>
203	              <FormSelect
204	                value={props.listener.tlsMode}
205	                id={`addTlsMode_${props.index}`}
206	                name="addTlsMode"
207	                onChange={onAddTlsMode}
208	              >
209	                {tlsModes.map((option, index) => (
210	                  <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
211	                ))}
212	              </FormSelect>
213	            </FormGroup>
214	          </Td>
215	          {props.listener.tlsMode === TERMINATE && (
216	            <Td colSpan={4}>
217	              <FormGroup
218	                label="TLS Certificate"
219	                style={{ margin: '0.5rem 0' }}
220	                isRequired={true}
221	                fieldId="server-certificate"
222	              >
223	                <TextInput
224	                  value={props.listener.tlsCert}
225	                  isRequired={true}
226	                  type="text"
227	                  id={`tlsCert_${props.index}`}
228	                  aria-describedby="server-certificate"
229	                  name="tls-certificate"
230	                  onChange={onAddTlsCert}
231	                  validated={isValid(props.listener.tlsCert.length > 0)}
232	                />
233	              </FormGroup>
234	            </Td>
235	          )}
236	        </Tr>
237	      )}
238	    </>
239	  );
240	};

